import { useRef, useState, useEffect } from 'react'
import { useParams } from 'react-router-dom'
import html2canvas from 'html2canvas'
import printProducts from '../data/printProducts'

export default function ProductCustomizer() {

  const mockupRef = useRef(null)

  const { id } = useParams()

  const product = printProducts.find(
    item => item.id === id
  )

  const presetBoxes = {

    // FRONT LOCKED
    front: {
      x: 50,
      y: 35,
      width: 228,
      height: 280,
      zoom: 100
    },

    // LEFT CHEST LOCKED
    'left-chest': {
      x: 57.25,
      y: 28.5,
      width: 84,
      height: 78,
      zoom: 100
    },

    // BACK LOCKED
    back: {
      x: 50,
      y: 34,
      width: 245,
      height: 298,
      zoom: 100
    }
  }

  const [selectedColor, setSelectedColor] =
    useState(product.colors[0])

  const [uploadedLogo, setUploadedLogo] =
    useState(null)

  const [logoScale, setLogoScale] =
    useState(100)

  const [activePreset, setActivePreset] =
    useState('front')

  const [dragEnabled, setDragEnabled] =
    useState(false)

  const [customPosition, setCustomPosition] =
    useState({
      x: presetBoxes.front.x,
      y: presetBoxes.front.y
    })

  const [boxWidth, setBoxWidth] =
    useState(
      presetBoxes.front.width
    )

  const [boxHeight, setBoxHeight] =
    useState(
      presetBoxes.front.height
    )

  const [isDragging, setIsDragging] =
    useState(false)

  useEffect(() => {

    const preset =
      presetBoxes[activePreset]

    setCustomPosition({
      x: preset.x,
      y: preset.y
    })

    setBoxWidth(
      preset.width
    )

    setBoxHeight(
      preset.height
    )

    setLogoScale(
      preset.zoom
    )

  }, [activePreset])

  const handleUpload = (e) => {

    const file =
      e.target.files[0]

    if (!file) return

    const imageUrl =
      URL.createObjectURL(file)

    setUploadedLogo(
      imageUrl
    )
  }

  const setPreset = (type) => {

    setActivePreset(type)
  }

  const removeLogo = () => {

    setUploadedLogo(null)
  }

  const exportMockup = async () => {

    const canvas =
      await html2canvas(
        mockupRef.current,
        {
          backgroundColor: null,
          scale: 3,
          useCORS: true
        }
      )

    const image =
      canvas.toDataURL(
        'image/png'
      )

    const link =
      document.createElement(
        'a'
      )

    link.href = image

    link.download =
      `mockup-${activePreset}.png`

    link.click()
  }

  const handleMouseMove = (e) => {

    if (
      !dragEnabled ||
      !isDragging
    ) return

    const rect =
      e.currentTarget.getBoundingClientRect()

    const x =
      (
        (
          e.clientX -
          rect.left
        ) /
        rect.width
      ) * 100

    const y =
      (
        (
          e.clientY -
          rect.top
        ) /
        rect.height
      ) * 100

    const limitedX =
      Math.max(
        10,
        Math.min(90, x)
      )

    const limitedY =
      Math.max(
        10,
        Math.min(90, y)
      )

    setCustomPosition({
      x: limitedX,
      y: limitedY
    })
  }

  return (

    <div
      className="h-screen bg-black text-white overflow-hidden"
      onMouseMove={
        handleMouseMove
      }
      onMouseUp={() =>
        setIsDragging(false)
      }
    >

      <div className="grid grid-cols-1 xl:grid-cols-[65%_35%] h-full">

        <div
          ref={mockupRef}
          className="bg-[#e9e9e9] flex items-center justify-center relative p-10 w-full h-full overflow-hidden"
        >

          <img
            src={
              activePreset === 'back'
                ? selectedColor.backImage
                : selectedColor.image
            }
            alt="product"
            className="w-full max-w-[700px] max-h-[88vh] object-contain"
          />

          <div
            className={`absolute flex items-center justify-center ${
              dragEnabled
                ? 'cursor-move'
                : ''
            }`}
            style={{
              width:
                `${boxWidth}px`,
              height:
                `${boxHeight}px`,
              top:
                `${customPosition.y}%`,
              left:
                `${customPosition.x}%`,
              transform:
                'translate(-50%, -50%)',

              border:
                activePreset === 'left-chest'
                  ? '2px solid #ff4d4d'
                  : (
                      dragEnabled
                        ? '2px solid #ff4d4d'
                        : 'none'
                    )
            }}
            onMouseDown={() => {

              if (
                dragEnabled
              ) {
                setIsDragging(true)
              }
            }}
          >

            {uploadedLogo && (

              <img
                src={uploadedLogo}
                alt="logo"
                className="select-none pointer-events-none"
                style={{
                  width: '100%',
                  height: '100%',

                  objectFit: 'fill',

                  transform: `
                    scale(${logoScale / 100})
                  `
                }}
                draggable={false}
              />

            )}

          </div>

        </div>

        <div className="bg-black border-l border-[#1d1d1d] flex flex-col h-full overflow-y-auto">

          <div className="border-b border-[#1d1d1d] p-6">

            <p className="text-yellow-500 text-[10px] tracking-[0.3em] uppercase mb-2">
              Inspired By God
            </p>

            <h1 className="text-4xl font-black">
              {product.name}
            </h1>

          </div>

          <div className="p-6 space-y-6">

            <div>

              <h2 className="text-sm font-black mb-4">
                Shirt Colors
              </h2>

              <div className="grid grid-cols-2 gap-3">

                {product.colors.map(
                  (color) => (

                    <button
                      key={color.name}
                      onClick={() =>
                        setSelectedColor(
                          color
                        )
                      }
                      className={`p-4 rounded-xl text-xs font-black capitalize ${
                        selectedColor.name ===
                        color.name
                          ? 'bg-yellow-500 text-black'
                          : 'bg-[#111] border border-[#222]'
                      }`}
                    >
                      {color.name}
                    </button>

                  ))}

              </div>

            </div>

            <div>

              <h2 className="text-sm font-black mb-4">
                Placement
              </h2>

              <div className="grid grid-cols-1 gap-3">

                {[
                  'front',
                  'left-chest',
                  'back'
                ].map((item) => (

                  <button
                    key={item}
                    onClick={() =>
                      setPreset(item)
                    }
                    className={`p-4 rounded-xl text-xs font-black ${
                      activePreset === item
                        ? 'bg-yellow-500 text-black'
                        : 'bg-[#111] border border-[#222]'
                    }`}
                  >
                    {item}
                  </button>

                ))}

              </div>

            </div>

            <div className="grid grid-cols-2 gap-3">

              <button
                onClick={() =>
                  setCustomPosition(prev => ({
                    ...prev,
                    x: 50
                  }))
                }
                className="bg-[#111] border border-[#222] py-4 rounded-xl text-xs font-black"
              >
                CENTER X
              </button>

              <button
                onClick={() =>
                  setCustomPosition(prev => ({
                    ...prev,
                    y: 50
                  }))
                }
                className="bg-[#111] border border-[#222] py-4 rounded-xl text-xs font-black"
              >
                CENTER Y
              </button>

            </div>

            <button
              onClick={() =>
                setDragEnabled(
                  !dragEnabled
                )
              }
              className={`w-full py-4 rounded-xl text-xs font-black ${
                dragEnabled
                  ? 'bg-yellow-500 text-black'
                  : 'bg-[#111] border border-[#222]'
              }`}
            >
              {dragEnabled
                ? 'DRAG MODE ON'
                : 'DRAG MODE OFF'}
            </button>

            <div>

              <h2 className="text-sm font-black mb-4">
                Upload Logo
              </h2>

              <input
                type="file"
                accept="image/png,image/jpeg"
                onChange={
                  handleUpload
                }
                className="w-full bg-[#111] border border-[#222] rounded-xl p-4 text-sm"
              />

            </div>

            {uploadedLogo && (

              <>

                <button
                  onClick={
                    removeLogo
                  }
                  className="w-full border border-red-500 text-red-500 py-4 rounded-xl text-xs font-black"
                >
                  REMOVE LOGO
                </button>

                <button
                  onClick={
                    exportMockup
                  }
                  className="w-full bg-white text-black py-4 rounded-xl text-xs font-black"
                >
                  EXPORT MOCKUP
                </button>

                <div>

                  <div className="flex justify-between mb-3">

                    <p className="text-xs text-white/60">
                      Zoom
                    </p>

                    <p className="text-xs text-yellow-500 font-black">
                      {logoScale}%
                    </p>

                  </div>

                  <input
                    type="range"
                    min="50"
                    max="180"
                    value={logoScale}
                    onChange={(e) =>
                      setLogoScale(
                        e.target.value
                      )
                    }
                    className="w-full"
                  />

                </div>

              </>

            )}

          </div>

        </div>

      </div>

    </div>

  )
}
